func countOccurrences(_ s: String) -> [Int] {
    var cnt = Array(repeating: 0, count: 10)
    for c in s {
        let digit = Int(c.asciiValue! - 48)
        if digit < 0 || digit > 9 { continue }
        cnt[digit] += 1
    }
    return cnt
}

func isPalindrome(_ s: String) -> Bool {
    let chars = Array(s)
    var i = 0
    var j = chars.count - 1
    while i < j {
        if chars[i] != chars[j] {
            return false
        }
        i += 1
        j -= 1
    }
    return true
}

func solve(n: Int64) -> Int64 {
    var x = n + 1
    while true {
        let s = String(x)
        if isPalindrome(s) {
            let cnt = countOccurrences(s)
            var valid = true
            for k in 0..<cnt.count {
                if cnt[k] == 0 {
                    continue
                }
                if k == 0 || cnt[k] != k {
                    valid = false
                    break
                }
            }
            if valid {
                return x
            }
        }
        x += 1
    }
}
